VALUES
  ('judicial-57f41407-moex-00353', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '服務燒傷顏損者的陽光基金會自2014年起取「你我一起」諧音，訂每年5月17日為「臉部平權日」， 期待能讓不同長相的人，都能在友善的社會中實踐自我。據其2022年最新調查結果顯示：每7個人 中會有1人因外表遭遇不友善對待，外觀有顯著特徵者更容易因此喪失就業機會。陽光基金會更於公 共政策網路參與平台提出將臉部平權日列入國家紀念日，透過國家力量讓每個人皆能安心發展所長、 實踐夢想。關於上述情況，下列何者正確？', '["陽光基金會屬於第二部門", "公共政策網路參與平台增加民眾政治參與的管道", "推動臉部平權日為由上而下的公民行動", "於公共政策網路平台的提案屬於公民不服從的展現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00354', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2017年12月公民投票法部分條文修正通過，將公投年齡從20歲降至18歲，並大幅降低提案、成案 及通過的門檻。關於公民投票法的敘述，何者正確？', '["其修正案須由公民投票複決通過", "增加人民政治參與的困難度", "能實現人民選舉與罷免的權利", "能增進人民直接民權的行使"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00355', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '近年來，社會日趨認同家務勞動是社會、家庭和個人生產得以維繫的重要關鍵，下列敘述何者屬於「家 務勞動」的範疇？', '["疫情期間在家做代工打發時間", "放無薪假的期間在家裏帶小孩", "擔任老人居家看護賺取零用錢", "下班後經營網路拍賣增加收入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00356', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '在民主國家，公共利益的推動經常是透過公民團體的倡議來達成，下列敘述何者最符合？', '["某學校家長會開記者會批評政府停課標準存在疏漏，使家長與學生無所適從", "網友們強烈要求政府儘快進口「德國唾液快篩劑」，價格親民又免捅鼻之苦", "新二代在社群網絡建立「新二代留聲機」專欄串聯發聲要找回生命自主權", "醫生們自拍影片宣達空污嚴重影響健康，呼籲政府必須重視，搶救下一代"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00357', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '為落實直接民權與主權在民，我國制定有公民投票法，以增進決策的合法性與正當性。根據該法之規 定，下列何者可透過公投來決定？', '["為落實居住正義，對持有三間房屋以上者課囤房稅", "縣長施政滿意度低，縣議員發動公投決定縣長去留", "市長為落實公民參與，以公投強化預算編列正當性", "某市規劃以公投決定空污防制自治條例的立法原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00358', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '根據憲法，人民擁有選舉與罷免權。依我國公職人員選舉罷免法的相關規定，關於罷免通過門檻的敘 述，下列何者正確？', '["同意罷免的有效票總數大於不同意罷免的有效票總數即可", "罷免投票的投票率必須達原選舉區選舉人總數的1/2以上", "除同意票須大於不同意票外，同意票數須達選舉人總數1/4", "同意罷免的票數須大於反對票數，且高於當初當選的票數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00359', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '立法院於民國103年三讀通過「地方制度法」部分條文的修正，增訂直轄市山地原住民區實施自治的 法源及其配套規定。請問：有關我國直轄市山地原住民區的相關敘述，下列何者正確？', '["行政機關為山地原住民區公所", "立法機關為山地原住民區議會", "區長由直轄市市長直接派出，任期四年", "區民代表任期為四年，連選得連任一次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00360', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '綠色和平是獨立的國際環保組織，致力於通過科學研究、政策倡議及和平行動，揭露全球環境問題， 也推動政府、企業與公眾共同尋求環境問題的解決方案。下列何者不是其組織運作最有可能出現的模 式？', '["透過媒體表達訴求，影響輿論，使社會接納其理念", "對政府機關進行遊說，表達對某政策的立場或主張", "針對妨害其訴求之法令或事件，請求司法機關裁判", "匯集民意提名候選人參選，贏得執政以實現其利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00361', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2022年美國總統拜登與中國國家主席習近平舉行視訊會議，習近平重申「一個中國原則」，而拜登則 強調以臺灣關係法與美中三公報的「一個中國政策」，堅決反對片面改變現狀或破壞臺海和平穩定的 作為。根據上述內容來分析臺海兩岸關係，下列何者錯誤？', '["中國認為兩岸對一個中國內涵，存在各自表述的空間", "中國主張世界上只有一個中國，臺灣是中國的一部分", "美國認為中華人民共和國是代表中國的唯一合法政府", "美國為避免中國片面改變現狀，可出售防禦性武器給臺灣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00362', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「民主正當性」是指國家權力之表現須以人民意志為出發點，且以大多數人民之同意作為基礎，而取 得其正當性。下列何者是基於民主正當性而來的具體要求？', '["以國家考試作為任用公務員之錄取標準", "監察委員由總統提名後須經立法院同意", "外國人歸化我國須取得內政部之許可", "選舉罷免訴訟依法由普通法院進行審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
